const source = $('Build Delete Query').first()?.json ?? {};
const row = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const formatDateTime = (value) => {
  const raw = clean(value);
  if (!raw) return 'Not available';
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return raw;
  return date.toLocaleString('en-GB', { dateStyle: 'medium', timeStyle: 'short' });
};
const batchId = clean(row.batch_id || source.batch_id);
const sourceId = clean(row.source_id || source.source_id);
const sourceTable = clean(row.source_table || source.source_table) || 'signup_batch_manual_items';
const isManual = sourceTable === 'signup_batch_manual_items';
const itemLabel = isManual ? 'Manual Item' : 'Captured Signup';
const titleSubject = isManual ? 'Manual Batch Item' : 'Captured Signup';
const n8nBaseUrl = clean(source.n8n_base_url) || 'http://n8n:5678';
const reviewUrl = `${n8nBaseUrl}/webhook/signup-batch-review?batch_id=${encodeURIComponent(batchId)}&_ts=${Date.now()}`;
const selfUrl = `${n8nBaseUrl}/webhook/delete-manual-batch-item`;
const itemExists = row.item_exists === true || clean(row.item_exists).toLowerCase() === 'true';
const canDelete = row.can_delete === true || clean(row.can_delete).toLowerCase() === 'true';
const confirmDelete = row.confirm_delete === true || clean(source.confirm_delete).toLowerCase() === 'true';
const deleted = row.deleted === true || clean(row.deleted).toLowerCase() === 'true';
const batchStatus = clean(row.batch_status) || 'Unknown';
const responseCode = !itemExists ? 404 : confirmDelete && !deleted ? 409 : 200;
const details = [
  ['Batch', batchId],
  [itemLabel, sourceId],
  ['Added', formatDateTime(row.item_date)],
  ['Member', row.member],
  ['Payer', row.payer],
  ['Product', row.product],
  ['Shoe Tags', row.regular_tags],
  ['Parents', row.parent_tags],
  ['Keys', row.key_tags],
  ['Notes', row.notes],
].filter(([, value]) => clean(value) !== '' && clean(value) !== 'Not available');
const detailHtml = details.map(([label, value]) => `<div class="detail"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`).join('');
let badge = 'Action needed';
let badgeClass = 'badge warning';
let title = isManual ? 'Delete Manual Batch Item' : 'Remove Captured Signup From Batch';
let message = isManual
  ? 'Review the manual batch item below before deleting it permanently.'
  : 'Review the captured signup below before removing it from this batch.';
let actionHtml = `<form method="get" action="${selfUrl}"><input type="hidden" name="batch_id" value="${escapeHtml(batchId)}"><input type="hidden" name="source_id" value="${escapeHtml(sourceId)}"><input type="hidden" name="source_table" value="${escapeHtml(sourceTable)}"><input type="hidden" name="confirm" value="1"><div class="actions"><button class="button danger" type="submit">${isManual ? 'Delete Item Permanently' : 'Remove From Batch'}</button><a class="button secondary" href="${reviewUrl}">Back to Review</a><button type="button" class="button secondary" onclick="window.close()">Close</button></div></form>`;
if (!itemExists) {
  badge = 'Not found';
  badgeClass = 'badge error';
  title = `${titleSubject} Not Found`;
  message = `The requested ${titleSubject.toLowerCase()} no longer exists for this batch.`;
  actionHtml = `<div class="actions"><a class="button secondary" href="${reviewUrl}">Back to Review</a><button type="button" class="button secondary" onclick="window.close()">Close</button></div>`;
} else if (!canDelete) {
  badge = 'Locked';
  badgeClass = 'badge error';
  title = 'Deletion Not Available';
  message = `${titleSubject}s can only be changed while the batch is Processing. Current status: ${batchStatus}.`;
  actionHtml = `<div class="actions"><a class="button secondary" href="${reviewUrl}">Back to Review</a><button type="button" class="button secondary" onclick="window.close()">Close</button></div>`;
} else if (deleted) {
  badge = 'Deleted';
  badgeClass = 'badge success';
  title = isManual ? 'Manual Batch Item Deleted' : 'Captured Signup Removed';
  message = isManual
    ? 'The manual batch item was removed permanently from this batch.'
    : 'The captured signup was removed from this batch and reset to New so it can be re-batched later.';
  actionHtml = `<div class="actions"><a class="button secondary" href="${reviewUrl}">Back to Review</a><button type="button" class="button secondary" onclick="window.close()">Close</button></div>`;
} else if (confirmDelete) {
  badge = 'Action needed';
  badgeClass = 'badge error';
  title = 'Delete Did Not Complete';
  message = 'The delete request did not complete. Reload the review page and try again.';
  actionHtml = `<div class="actions"><a class="button secondary" href="${reviewUrl}">Back to Review</a><button type="button" class="button secondary" onclick="window.close()">Close</button></div>`;
}
const warningMessage = isManual
  ? 'This is a hard delete. The manual batch item will be removed permanently from labels, envelopes, exports, and batch totals.'
  : 'This does not delete the captured signup record. It only removes the signup from the current batch, resets its status to New, and updates the batch totals.';
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${escapeHtml(title)}</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f7f8fc;
      --panel: #ffffff;
      --ink: #2e3d4e;
      --muted: #6b7785;
      --line: #e2e8f0;
      --accent: #509ee3;
      --danger: #b42318;
      --danger-soft: #fef3f2;
      --success: #166534;
      --success-soft: #ecfdf3;
      --warning: #9a6700;
      --warning-soft: #fff7ed;
      --button-soft: #eef2f7;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      padding: 24px;
      font-family: Lato, 'Helvetica Neue', Arial, sans-serif;
      color: var(--ink);
      background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%);
    }
    .panel {
      max-width: 820px;
      margin: 0 auto;
      background: var(--panel);
      border: 1px solid var(--line);
      border-radius: 18px;
      padding: 28px;
      box-shadow: 0 18px 40px rgba(53, 72, 91, 0.08);
    }
    .badge {
      display: inline-flex;
      padding: 6px 12px;
      border-radius: 999px;
      font-size: 13px;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 0.04em;
    }
    .badge.warning { color: var(--warning); background: var(--warning-soft); }
    .badge.error { color: var(--danger); background: var(--danger-soft); }
    .badge.success { color: var(--success); background: var(--success-soft); }
    h1 {
      margin: 16px 0 8px;
      font-size: 32px;
      line-height: 1.1;
    }
    p {
      margin: 0;
      color: var(--muted);
      line-height: 1.6;
      font-size: 16px;
    }
    .warning-box {
      margin-top: 18px;
      padding: 16px 18px;
      border-radius: 14px;
      border: 1px solid #fecdca;
      background: var(--danger-soft);
      color: var(--danger);
      font-weight: 700;
      line-height: 1.5;
    }
    .details {
      display: grid;
      gap: 12px;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
      margin-top: 24px;
    }
    .detail {
      border: 1px solid var(--line);
      border-radius: 14px;
      padding: 14px 16px;
      background: #f8fafc;
    }
    .detail span {
      display: block;
      margin-bottom: 6px;
      color: var(--muted);
      font-size: 13px;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 0.04em;
    }
    .detail strong {
      font-size: 17px;
      line-height: 1.4;
      word-break: break-word;
    }
    .actions {
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
      margin-top: 24px;
    }
    .button {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      padding: 12px 18px;
      border-radius: 999px;
      font: inherit;
      font-weight: 700;
      text-decoration: none;
      border: 0;
      cursor: pointer;
    }
    .button.danger {
      color: #fff;
      background: linear-gradient(135deg, var(--danger) 0%, #912018 100%);
      box-shadow: 0 10px 24px rgba(180, 35, 24, 0.22);
    }
    .button.secondary {
      color: var(--ink);
      background: var(--button-soft);
      border: 1px solid var(--line);
    }
  </style>
</head>
<body>
  <main class="panel">
    <span class="${badgeClass}">${escapeHtml(badge)}</span>
    <h1>${escapeHtml(title)}</h1>
    <p>${escapeHtml(message)}</p>
    ${!deleted && itemExists && canDelete ? `<div class="warning-box">${escapeHtml(warningMessage)}</div>` : ''}
    ${detailHtml ? `<section class="details">${detailHtml}</section>` : ''}
    ${actionHtml}
  </main>
</body>
</html>`;
return [{ json: { ...row, response_code: responseCode, html } }];
